/*import { useState, useEffect } from "react";
import { Link, useLocation } from "react-router-dom"; 
import API from '../api/axios';
import "../App.css";

/* ==========================================================
   NAVIGATION COMPONENT
   ========================================================== 
function Nav() {
  const location = useLocation();

  const applyTheme = (mode) => {
    const body = document.body;
    if (mode === "dark") {
      body.classList.add("dark-mode");
      localStorage.setItem("user-theme", "dark");
    } else {
      body.classList.remove("dark-mode");
      localStorage.setItem("user-theme", "light");
    }
    window.dispatchEvent(new Event("storage"));
  };

  useEffect(() => {
    const savedTheme = localStorage.getItem("user-theme");
    const systemPrefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
    if (savedTheme === "dark") applyTheme("dark");
    else if (savedTheme === "light") applyTheme("light");
    else applyTheme(systemPrefersDark ? "dark" : "light");
  }, []);

  const toggleTheme = () => {
    const isDark = document.body.classList.contains("dark-mode");
    applyTheme(isDark ? "light" : "dark");
  };

  const isActive = (path) => location.pathname === path ? "active" : "";

  
}

/* ==========================================================
   REGISTER PAGE COMPONENT
   ========================================================== 
function RegisterPage() {
  const [formData, setFormData] = useState({
    fullName: "",
    username: "",
    dob: "",
    email: "",
    password: "",
    confirmPassword: "",
    gender: "",
    accountType: "",
    category: "",
    terms: false
  });

  const [errors, setErrors] = useState({});
  const [successMessage, setSuccessMessage] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === "checkbox" ? checked : value
    }));
  };

  const validateForm = () => {
    let newErrors = {};
    if (!formData.fullName.trim()) newErrors.fullName = "Full name is required";
    if (!formData.username.trim()) newErrors.username = "Username is required";
    if (!formData.dob) newErrors.dob = "Date of birth is required";
    if (!formData.email.includes("@")) newErrors.email = "Valid email is required";
    if (formData.password.length < 6) newErrors.password = "Password must be at least 6 characters";
    if (formData.password !== formData.confirmPassword) newErrors.confirmPassword = "Passwords do not match";
    if (!formData.gender) newErrors.gender = "Select gender";
    if (!formData.accountType) newErrors.accountType = "Select account type";
    if (!formData.category) newErrors.category = "Select category";
    if (!formData.terms) newErrors.terms = "You must agree to terms";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (validateForm()) {
      try {
        await API.post('/auth/register', {
          name: formData.fullName,
          username: formData.username,
          email: formData.email,
          password: formData.password,
          role: formData.accountType === 'admin' ? 'admin' : 'member'
        });
        setSuccessMessage("Registration successful! You can now login.");
        setTimeout(() => {
          window.location.href = '/login';
        }, 2000);
        setFormData({
          fullName: "", username: "", dob: "", email: "",
          password: "", confirmPassword: "", gender: "",
          accountType: "", category: "", terms: false
        });
        setErrors({});
      } catch (err) {
        setErrors({ submit: err.response?.data?.message || 'Registration failed' });
      }
    }
  };

  const alignedLabel = {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    cursor: "pointer",
    fontWeight: "normal",
    fontSize: "15px"
  };

  return (
    <>
      <Nav />
      <main className="content-wrapper">
        <div className="register-intro">
          <h2>Join My Art & Crafts Community</h2>
          <p>Let’s connect and create! Send a message to share ideas, ask questions, or find art and craft inspiration.</p>
        </div>

        <section className="register-layout">
          <div className="why-signup-box">
            <h3>Why Sign Up?</h3>
            <p>By signing up, you will receive updates about creative art ideas, craft tutorials, design inspiration, and helpful tips.</p>
            <img src="/pictures/paint5.png" alt="Art inspiration" className="decorative-img" />
            <div className="benefits-grid">
                <div className="benefit-item">
                    <span className="benefit-icon">📚</span>
                    <div>
                        <h4>Tutorials</h4>
                        <p>Step-by-step craft guides.</p>
                    </div>
                </div>
                <div className="benefit-item">
                    <span className="benefit-icon">✨</span>
                    <div>
                        <h4>Inspiration</h4>
                        <p>Daily creative sparks.</p>
                    </div>
                </div>
                <div className="benefit-item">
                    <span className="benefit-icon">🛠️</span>
                    <div>
                        <h4>Resources</h4>
                        <p>Free design assets.</p>
                    </div>
                </div>
                <div className="benefit-item">
                    <span className="benefit-icon">🤝</span>
                    <div>
                        <h4>Community</h4>
                        <p>Connect with artists.</p>
                    </div>
                </div>
            </div>
            <p className="disclaimer">This form is for educational portfolio demonstration only.</p>
          </div>

          <div className="form-container">
            <form className="register-form" onSubmit={handleSubmit}>
              
{(successMessage || errors.submit) && (
                <div style={{ 
                  backgroundColor: successMessage ? "#d4edda" : "#f8d7da", 
                  color: successMessage ? "#155724" : "#721c24", 
                  padding: "15px", 
                  borderRadius: "8px", 
                  border: `1px solid ${successMessage ? "#c3e6cb" : "#f5c6cb"}`, 
                  textAlign: "center", 
                  marginBottom: "20px", 
                  fontWeight: "bold" 
                }}>
                  {successMessage || errors.submit}
                </div>
              )}

              <div className="form-group">
                <label>Full Name</label>
                <input name="fullName" value={formData.fullName} onChange={handleChange} placeholder="Enter full name" />
                <span className="error-message">{errors.fullName}</span>
              </div>

              <div className="form-group">
                <label>Username</label>
                <input name="username" value={formData.username} onChange={handleChange} placeholder="Enter username" />
                <span className="error-message">{errors.username}</span>
              </div>

              <div className="form-group">
                <label htmlFor="accountType">Account Type:</label>
                <select 
                  name="accountType" 
                  id="accountType" 
                  className="account-type-select"
                  value={formData.accountType} 
                  onChange={handleChange}
                >
                  <option value="">Select Account Type</option>
                  <option value="basic">Basic</option>
                  <option value="premium">Premium</option>
                  <option value="admin">Admin</option>
                </select>
                <span className="error-message">{errors.accountType}</span>
              </div>

              <div className="form-group">
                <label>Date of Birth</label>
                <input type="date" name="dob" value={formData.dob} onChange={handleChange} />
                <span className="error-message">{errors.dob}</span>
              </div>

              <div className="form-group">
                <label>Email</label>
                <input name="email" value={formData.email} onChange={handleChange} placeholder="example@mail.com" />
                <span className="error-message">{errors.email}</span>
              </div>

              <div className="form-group" style={{ marginBottom: "20px" }}>
                <label style={{ fontWeight: "bold", marginBottom: "10px", display: "block" }}>Select your interest category:</label>
                <div style={{ display: "flex", flexWrap: "wrap", gap: "15px", marginTop: "5px" }}>
                  <label style={alignedLabel}>
                    <input type="radio" name="category" value="beginner" checked={formData.category === "beginner"} onChange={handleChange} /> Beginner
                  </label>
                  <label style={alignedLabel}>
                    <input type="radio" name="category" value="intermediate" checked={formData.category === "intermediate"} onChange={handleChange} /> Intermediate
                  </label>
                  <label style={alignedLabel}>
                    <input type="radio" name="category" value="expert" checked={formData.category === "expert"} onChange={handleChange} /> Expert
                  </label>
                </div>
                <span className="error-message">{errors.category}</span>
              </div>

              <div className="form-group">
                <label>Gender:</label>
                <div style={{ display: "flex", gap: "20px", marginTop: "8px" }}>
                  <label style={alignedLabel}>
                    <input type="radio" name="gender" value="male" checked={formData.gender === "male"} onChange={handleChange} /> Male
                  </label>
                  <label style={alignedLabel}>
                    <input type="radio" name="gender" value="female" checked={formData.gender === "female"} onChange={handleChange} /> Female
                  </label>
                  <label style={alignedLabel}>
                    <input type="radio" name="gender" value="other" checked={formData.gender === "other"} onChange={handleChange} /> Other
                  </label>
                </div>
                <span className="error-message">{errors.gender}</span>
              </div>

              <div className="form-group password-wrapper">
                <label>Password</label>
                <input type={showPassword ? "text" : "password"} name="password" value={formData.password} onChange={handleChange} />
                <button type="button" className="toggle-icon" onClick={() => setShowPassword(!showPassword)}></button>
                <span className="error-message">{errors.password}</span>
              </div>

              <div className="form-group password-wrapper">
                <label>Confirm Password</label>
                <input type={showConfirmPassword ? "text" : "password"} name="confirmPassword" value={formData.confirmPassword} onChange={handleChange} />
                <button type="button" className="toggle-icon" onClick={() => setShowConfirmPassword(!showConfirmPassword)}></button>
